router = APIRouter()


@router.get("/export.csv")
async def export_repositorios_csv(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(require_permission(P.INVENTORY.REPOS_EXPORT)),
):
    """Exporta repositorios del usuario a CSV; auditoría A7 (BRD A3)."""
    items = await repositorio_svc.list(db, filters={"user_id": current_user.id})
    buf = StringIO()
    writer = csv.writer(buf)
    writer.writerow(
        [
            "id",
            "nombre",
            "url",
            "plataforma",
            "rama_default",
            "activo",
            "organizacion_id",
            "celula_id",
            "subdireccion_responsable_id",
            "responsable_nombre",
            "responsable_contacto",
        ]
    )
    for r in items:
        writer.writerow(
            [
                str(r.id),
                r.nombre,
                r.url,
                r.plataforma,
                r.rama_default,
                r.activo,
                str(r.organizacion_id),
                str(r.celula_id) if r.celula_id else "",
                str(r.subdireccion_responsable_id) if r.subdireccion_responsable_id else "",
                r.responsable_nombre or "",
                r.responsable_contacto or "",
            ]
        )
    body = buf.getvalue()
    digest = hashlib.sha256(body.encode("utf-8")).hexdigest()
    await audit_record(
        db,
        action="repositorio.export_csv",
        entity_type="repositorio",
        entity_id=current_user.id,
        metadata={"rows": len(items), "sha256": digest, "format": "csv"},
    )
    return Response(
        content=body,
        media_type="text/csv; charset=utf-8",
        headers={"Content-Disposition": 'attachment; filename="repositorios.csv"'},
    )


